#!/usr/bin/env python3
"""
# HCI - Cluster Provisioning Script (Nutanix Foundation equivalent)
This script runs locally to bootstrap the 3 Enterprise Linux (EL) 10.2 hosts.
It handles:
  1. Parsing CLI arguments for force execution
  2. SSH connection (attempts SSH key first, falls back to password credentials)
  3. SSH public key exchange for passwordless authentication (if password used)
  4. Copying private/public SSH keys to hosts to enable inter-node passwordless SSH mesh
  5. Hostname check and auto-assignment (reboot if hostname not set to Valkyrie-XXXXXX)
  6. Installation of KVM, libvirt, Podman, and NFS utilities on target hosts
  7. Generation and synchronization of /etc/hci/ configurations
  8. Deployment of Podman Quadlets to /etc/containers/systemd/
  9. Copying the cluster creation utility to /usr/local/bin/cluster
  10. Service startup and basic verification
"""

import os
import sys
import json
import socket
